<template><div class="page"><div class="toolbar"><h2>脚本编辑</h2><el-button type="primary" @click="newScript">新建脚本</el-button><el-select v-model="category" clearable placeholder="分类筛选" @change="load"><el-option label="带货" value="带货"/><el-option label="欢迎" value="欢迎"/><el-option label="互动" value="互动"/></el-select></div><div class="grid grid-2"><div class="card"><el-table :data="list" @row-click="edit"><el-table-column prop="title" label="标题"/><el-table-column prop="category" label="分类" width="100"/><el-table-column width="90"><template #default="s"><el-button link type="danger" @click.stop="remove(s.row.id)">删除</el-button></template></el-table-column></el-table></div><div class="card"><el-form label-position="top"><el-form-item label="标题"><el-input v-model="form.title"/></el-form-item><el-form-item label="分类"><el-input v-model="form.category"/></el-form-item><el-form-item label="内容"><el-input v-model="form.content" type="textarea" :rows="12"/></el-form-item><el-button type="primary" @click="save">保存</el-button></el-form></div></div></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage,ElMessageBox } from 'element-plus';import { getScriptList,createScript,updateScript,deleteScript } from '../api/scripts';const list=ref([]),category=ref('');const form=reactive({id:null,title:'',category:'',content:''});async function load(){list.value=await getScriptList(category.value?{category:category.value}:undefined)||[]}function newScript(){Object.assign(form,{id:null,title:'',category:'',content:''})}function edit(row){Object.assign(form,row)}async function save(){if(!form.title)return ElMessage.warning('请输入标题');const data={title:form.title,category:form.category,content:form.content};form.id?await updateScript(form.id,data):await createScript(data);ElMessage.success('保存成功');newScript();load()}async function remove(id){await ElMessageBox.confirm('确认删除脚本？','提示');await deleteScript(id);ElMessage.success('删除成功');load()}onMounted(load)</script>
